import { useState } from "react";

const tasks = [
  { id:"T-001",equipment:"MRI Scanner #A12",hospital:"City General Hospital",priority:"High",deadline:"2024-04-15",status:"Pending",description:"Annual calibration and safety check",image:"data:image/jpeg;base64,"},
  { id:"T-002",equipment:"Ventilator #B05",hospital:"Apollo Medical Center",priority:"Critical",deadline:"2024-04-12",status:"In Progress",description:"Alarm system malfunction — urgent fix needed",image:"data:image/jpeg;base64,"},
  { id:"T-003",equipment:"Defibrillator #C07",hospital:"City General Hospital",priority:"High",deadline:"2024-04-10",status:"In Progress",description:"Replace battery pack and test output",image:"data:image/jpeg;base64,"},
  { id:"T-004",equipment:"Infusion Pump #G01",hospital:"Sunrise Hospital",priority:"Medium",deadline:"2024-04-20",status:"Pending",description:"Flow rate calibration",image:"data:image/jpeg;base64,"},
  { id:"T-005",equipment:"X-Ray Machine #E01",hospital:"Apollo Medical Center",priority:"Low",deadline:"2024-04-08",status:"Completed",description:"Software firmware update",image:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSEBrljVMKXHguN5-b4rrm9OLgXPQlHPWCgpQ&s"},
  { id:"T-006",equipment:"CT Scanner #D02",hospital:"Metro Hospital",priority:"High",deadline:"2024-04-18",status:"Pending",description:"Cooling system inspection",image:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRnAjAk9dPxLAzqWrCgdrSIqUfx9ucfN8eQoA&s"},
  { id:"T-007",equipment:"ECG Monitor #H11",hospital:"Sunrise Hospital",priority:"Medium",deadline:"2024-04-22",status:"Pending",description:"Lead calibration check",image:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRJPrz4pCzF2OUaFQA8rvsoMZCk0oSC9hlj2A&s"},
  { id:"T-008",equipment:"Ultrasound Machine #U05",hospital:"Care Hospital",priority:"High",deadline:"2024-04-11",status:"In Progress",description:"Image resolution issue",image:"data:image/jpeg;base64,"},
  { id:"T-009",equipment:"Patient Monitor #P01",hospital:"City General Hospital",priority:"Low",deadline:"2024-04-25",status:"Pending",description:"Sensor replacement",image:"data:image/jpeg;base64,"},
  { id:"T-010",equipment:"Anesthesia Machine #AN03",hospital:"Metro Hospital",priority:"Critical",deadline:"2024-04-09",status:"In Progress",description:"Gas pressure issue",image:"data:image/jpeg;base64,"},
  { id:"T-011",equipment:"Dialysis Machine #DL09",hospital:"Apollo Medical Center",priority:"High",deadline:"2024-04-14",status:"Pending",description:"Pump pressure calibration",image:"data:image/jpeg;base64,"},
  { id:"T-012",equipment:"Ventilator #B09",hospital:"Care Hospital",priority:"Critical",deadline:"2024-04-13",status:"Pending",description:"Airflow sensor malfunction",image:"data:image/jpeg;base64,"},
  { id:"T-013",equipment:"Defibrillator #C11",hospital:"Metro Hospital",priority:"Medium",deadline:"2024-04-21",status:"Pending",description:"Battery test required",image:"data:image/jpeg;base64,"},
  { id:"T-014",equipment:"Infusion Pump #G08",hospital:"Sunrise Hospital",priority:"Low",deadline:"2024-04-23",status:"Pending",description:"Routine inspection",image:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSNRNpnMYd0ARq9VHBrbXgf4Jkg3sWOIY0RnQ&s"},
  { id:"T-015",equipment:"MRI Scanner #A18",hospital:"City General Hospital",priority:"High",deadline:"2024-04-17",status:"In Progress",description:"Magnet cooling system check",image:"data:image/jpeg;base64,"},
  { id:"T-016",equipment:"X-Ray Machine #E04",hospital:"Care Hospital",priority:"Medium",deadline:"2024-04-26",status:"Pending",description:"Detector alignment check",image:"data:image/jpeg;base64,"},
  { id:"T-017",equipment:"ECG Monitor #H21",hospital:"Metro Hospital",priority:"Low",deadline:"2024-04-24",status:"Pending",description:"Software patch update",image:"data:image/jpeg;base64,"},
  { id:"T-018",equipment:"CT Scanner #D05",hospital:"Apollo Medical Center",priority:"High",deadline:"2024-04-19",status:"Pending",description:"Radiation calibration",image:"data:image/jpeg;base64,"},
];

const priorityStyle = {
  Critical:"text-red-600 bg-red-50 border-red-200",
  High:"text-orange-600 bg-orange-50 border-orange-200",
  Medium:"text-yellow-600 bg-yellow-50 border-yellow-200",
  Low:"text-green-600 bg-green-50 border-green-200"
};

const statusStyle = {
  Pending:"bg-gray-100 text-gray-600",
  "In Progress":"bg-blue-100 text-blue-700",
  Completed:"bg-emerald-100 text-emerald-700"
};

export default function TaskList({ onNavigate }) {

  const [search,setSearch]=useState("");
  const [statusFilter,setStatusFilter]=useState("All");
  const [priorityFilter,setPriorityFilter]=useState("All");
  const [expanded,setExpanded]=useState(null);
  const [sortDeadline,setSortDeadline]=useState(false);

  let filtered=tasks.filter(t=>
    (statusFilter==="All"||t.status===statusFilter)&&
    (priorityFilter==="All"||t.priority===priorityFilter)&&
    (t.equipment.toLowerCase().includes(search.toLowerCase())||
    t.hospital.toLowerCase().includes(search.toLowerCase()))
  );

  if(sortDeadline){
    filtered=[...filtered].sort(
      (a,b)=>new Date(a.deadline)-new Date(b.deadline)
    );
  }

  const completed=tasks.filter(t=>t.status==="Completed").length;
  const open=tasks.filter(t=>t.status!=="Completed").length;
  const critical=tasks.filter(t=>t.priority==="Critical").length;
  const progress=(completed/tasks.length)*100;

  return (

    <div className="min-h-screen bg-sky-50">

      <div className="max-w-7xl mx-auto px-4 py-8">

        {/* HEADER */}

        <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 mb-6">

          <div>
            <h1 className="text-2xl font-bold text-gray-900">
              Maintenance Tasks
            </h1>
            <p className="text-gray-500 text-sm">
              Manage assigned repair tasks
            </p>
          </div>

          <button
            onClick={()=>setSortDeadline(!sortDeadline)}
            className="px-4 py-2 bg-white border border-sky-200 rounded-lg text-sm hover:bg-sky-100"
          >
            Sort by Deadline
          </button>

        </div>

        {/* ANALYTICS */}

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">

          <div className="bg-white border border-sky-200 rounded-xl p-4">
            <p className="text-xs text-gray-500">Total Tasks</p>
            <p className="text-xl font-bold">{tasks.length}</p>
          </div>

          <div className="bg-white border border-sky-200 rounded-xl p-4">
            <p className="text-xs text-gray-500">Open Tasks</p>
            <p className="text-xl font-bold text-sky-600">{open}</p>
          </div>

          <div className="bg-white border border-sky-200 rounded-xl p-4">
            <p className="text-xs text-gray-500">Critical</p>
            <p className="text-xl font-bold text-red-600">{critical}</p>
          </div>

          <div className="bg-white border border-sky-200 rounded-xl p-4">
            <p className="text-xs text-gray-500">Completed</p>
            <p className="text-xl font-bold text-emerald-600">{completed}</p>
          </div>

        </div>

        {/* PROGRESS */}

        <div className="bg-white border border-sky-200 rounded-xl p-4 mb-6">

          <p className="text-sm text-gray-600 mb-2">
            Overall Completion
          </p>

          <div className="w-full bg-sky-100 rounded-full h-2">

            <div
              className="bg-sky-500 h-2 rounded-full"
              style={{width:`${progress}%`}}
            />

          </div>

        </div>

        {/* FILTER */}

        <div className="grid md:grid-cols-3 gap-3 mb-6">

          <input
            type="text"
            placeholder="Search equipment or hospital..."
            value={search}
            onChange={(e)=>setSearch(e.target.value)}
            className="px-4 py-2 border border-sky-200 rounded-lg text-sm"
          />

          <select
            value={statusFilter}
            onChange={(e)=>setStatusFilter(e.target.value)}
            className="px-4 py-2 border border-sky-200 rounded-lg text-sm"
          >
            <option>All</option>
            <option>Pending</option>
            <option>In Progress</option>
            <option>Completed</option>
          </select>

          <select
            value={priorityFilter}
            onChange={(e)=>setPriorityFilter(e.target.value)}
            className="px-4 py-2 border border-sky-200 rounded-lg text-sm"
          >
            <option>All</option>
            <option>Critical</option>
            <option>High</option>
            <option>Medium</option>
            <option>Low</option>
          </select>

        </div>

        {/* TASK GRID */}

        <div className="grid md:grid-cols-3 gap-6">

          {filtered.map(task=>(

            <div
              key={task.id}
              className="bg-white border border-sky-200 rounded-xl p-5 hover:shadow-lg transition"
            >

              {/* IMAGE */}

              <div className="w-full h-44 bg-sky-100 rounded-lg flex items-center justify-center mb-4 overflow-hidden">

                {task.image ? (

                  <img
                    src={task.image}
                    alt={task.equipment}
                    className="w-full h-full object-contain"
                  />

                ) : (

                  <span className="text-gray-400 text-sm">
                    Image URL here
                  </span>

                )}

              </div>

              {/* EQUIPMENT */}

              <div className="flex flex-wrap items-center gap-2">

                <p className="font-semibold text-gray-900">
                  {task.equipment}
                </p>

                <span className={`text-xs px-2 py-0.5 rounded-full border ${priorityStyle[task.priority]}`}>
                  {task.priority}
                </span>

                <span className={`text-xs px-2 py-0.5 rounded-full ${statusStyle[task.status]}`}>
                  {task.status}
                </span>

              </div>

              <p className="text-sm text-gray-500 mt-1">
                {task.hospital}
              </p>

              {expanded===task.id&&(
                <p className="text-sm text-gray-600 mt-2">
                  {task.description}
                </p>
              )}

              <button
                onClick={()=>setExpanded(expanded===task.id?null:task.id)}
                className="text-xs text-sky-600 mt-2"
              >
                {expanded===task.id?"Hide details":"View details"}
              </button>

              <div className="flex items-center justify-between mt-4">

                <p className="text-xs text-gray-400">
                  {task.deadline}
                </p>

                {task.status!=="Completed"&&(
                  <button
                    onClick={()=>onNavigate("updatetask")}
                    className="px-4 py-2 bg-sky-600 text-white text-sm rounded-lg hover:bg-sky-700"
                  >
                    Update
                  </button>
                )}

              </div>

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}
